import { z } from 'zod/v4';

/**
 * Model IDs for PixelArt image generation.
 */
export type PixelArtImageModelId =
  | 'pixelart-standard'
  | 'pixelart-pro'
  | 'pixelart-ultra'
  | (string & {});

/**
 * Provider-specific settings for the PixelArt image model.
 * These are passed via `providerOptions.pixelart` in `generateImage` calls.
 */
export interface PixelArtImageSettings {
  /**
   * The size of the generated image (e.g. "256x256", "512x512", "1024x1024").
   * Overrides the standard `size` parameter when provided.
   */
  size?: string;

  /**
   * The artistic style to apply to the generated image.
   * - "pixel"  — classic pixel art style
   * - "retro"  — retro / vintage game aesthetic
   * - "8bit"   — 8-bit colour palette and dithering
   */
  style?: 'pixel' | 'retro' | '8bit';

  /**
   * The pixel density (dots-per-unit) of the generated image.
   * Higher values produce finer pixel grids.
   */
  pixelDensity?: number;
}

/**
