// Internal configuration (injected by the provider factory)
// ---------------------------------------------------------------------------

interface PixelArtImageModelConfig {
  provider: string;
  baseURL: string;
  headers?: Resolvable<Record<string, string | undefined>>;
  fetch?: FetchFunction;
  _internal?: {
    currentDate?: () => Date;
  };
}

// ---------------------------------------------------------------------------
// Response schema
// ---------------------------------------------------------------------------

const pixelArtImageResponseSchema = z.object({
  model: z.string().nullish(),
  images: z.array(
    z.object({
      b64_json: z.string(),
    }),
  ),
});

// ---------------------------------------------------------------------------
// Error schema / handler
// ---------------------------------------------------------------------------

const pixelArtErrorSchema = z.object({
  error: z
    .object({
      message: z.string(),
      type: z.string().nullish(),
      code: z.string().nullish(),
    })
    .nullish(),
  message: z.string().nullish(),
});

const pixelArtFailedResponseHandler = createJsonErrorResponseHandler({
  errorSchema: pixelArtErrorSchema,
  errorToMessage: error =>
    error.error?.message ?? error.message ?? 'Unknown PixelArt error',
});

// ---------------------------------------------------------------------------
// Image model class
// ---------------------------------------------------------------------------

export class PixelArtImageModel implements ImageModelV3 {
  readonly specificationVersion = 'v3';

  /**
   * PixelArt supports generating up to 4 images per call.
   */
  readonly maxImagesPerCall = 4;

  get provider(): string {
    return this.config.provider;
  }

  constructor(
    readonly modelId: PixelArtImageModelId,
    private readonly config: PixelArtImageModelConfig,
  ) {}

  async doGenerate(
    options: Parameters<ImageModelV3['doGenerate']>[0],
  ): Promise<Awaited<ReturnType<ImageModelV3['doGenerate']>>> {
    const { prompt, n, size, aspectRatio, seed, providerOptions, headers, abortSignal } =
      options;

    const warnings: Array<SharedV3Warning> = [];

    // Parse provider-specific options (passed as providerOptions.pixelart)
    const pixelArtOptions = await parseProviderOptions({
      provider: 'pixelart',
      providerOptions,
      schema: pixelArtImageSettingsSchema,
    });

    // PixelArt does not support aspect ratio — warn and ignore it
    if (aspectRatio != null) {
      warnings.push({
        type: 'unsupported-setting',
        setting: 'aspectRatio',
        details:
          'PixelArt does not support aspectRatio. Use the size setting instead.',
      });
    }

    // PixelArt does not support file-based image editing
    if (options.files != null && options.files.length > 0) {
      warnings.push({
        type: 'unsupported-setting',
        setting: 'files',
        details: 'PixelArt does not support image editing (input files).',
      });
    }

    if (options.mask != null) {
      warnings.push({
        type: 'unsupported-setting',
        setting: 'mask',
        details: 'PixelArt does not support inpainting (mask).',
      });
    }

    // Build request body
    const requestBody: Record<string, unknown> = {
      model: this.modelId,
      prompt,
      n,
      seed,
    };

    // Provider-level size takes precedence; fall back to the standard size param
    if (pixelArtOptions?.size != null) {
      requestBody.size = pixelArtOptions.size;
    } else if (size != null) {
      requestBody.size = size;
    }

    if (pixelArtOptions?.style != null) {
      requestBody.style = pixelArtOptions.style;
    }

    if (pixelArtOptions?.pixelDensity != null) {
      requestBody.pixel_density = pixelArtOptions.pixelDensity;
    }

    const currentDate = this.config._internal?.currentDate?.() ?? new Date();

    const { value, responseHeaders } = await postJsonToApi({
      url: `${this.config.baseURL}/images/generate`,
      headers: combineHeaders(await resolve(this.config.headers), headers),
      body: requestBody,
      failedResponseHandler: pixelArtFailedResponseHandler,
      successfulResponseHandler: createJsonResponseHandler(
        pixelArtImageResponseSchema,
      ),
      abortSignal,
      fetch: this.config.fetch,
    });

    return {
      images: value.images.map(img => img.b64_json),
      warnings,
      response: {
        modelId: value.model ?? this.modelId,
        timestamp: currentDate,
        headers: responseHeaders,
      },
    };
  }
}

