import {
  ImageModelV3,
  NoSuchModelError,
  ProviderV3,
} from '@ai-sdk/provider';
import type { FetchFunction } from '@ai-sdk/provider-utils';
import {
  withoutTrailingSlash,
  withUserAgentSuffix,
} from '@ai-sdk/provider-utils';
import { PixelArtImageModel } from './pixelart-image-model';
import type { PixelArtImageModelId } from './pixelart-image-settings';
import { VERSION } from './version';

// ---------------------------------------------------------------------------
// Provider settings
// ---------------------------------------------------------------------------

export interface PixelArtProviderSettings {
  /**
   * PixelArt API key. Defaults to the value of the `PIXELART_API_KEY`
   * environment variable.
   */
  apiKey?: string;

  /**
   * Base URL for the PixelArt API.
   * @default "https://api.pixelart.ai/v1"
   */
  baseURL?: string;

  /**
   * Additional HTTP headers to include in every request.
   */
  headers?: Record<string, string>;

  /**
   * Custom fetch implementation. Useful for middleware, testing, or
   * environments that require a non-standard fetch.
   */
  fetch?: FetchFunction;
}

// ---------------------------------------------------------------------------
// Provider interface
// ---------------------------------------------------------------------------

export interface PixelArtProvider extends ProviderV3 {
  /**
   * Creates a PixelArt image-generation model instance.
   *
   * @param modelId - The PixelArt model to use (e.g. "pixelart-standard").
   */
  image(modelId: PixelArtImageModelId): ImageModelV3;

  /**
   * Alias for {@link image}.
   */
  imageModel(modelId: PixelArtImageModelId): ImageModelV3;
}

// ---------------------------------------------------------------------------
// Internal helpers
// ---------------------------------------------------------------------------

const defaultBaseURL = 'https://api.pixelart.ai/v1';

function loadPixelArtApiKey({
  apiKey,
}: {
  apiKey: string | undefined;
}): string {
  if (typeof apiKey === 'string') {
    return apiKey;
  }

  if (apiKey != null) {
    throw new Error('PixelArt API key must be a string.');
  }

  if (typeof process === 'undefined') {
    throw new Error(
      "PixelArt API key is missing. Pass it using the 'apiKey' parameter. " +
        'Environment variables are not supported in this environment.',
    );
  }

  const envKey = process.env.PIXELART_API_KEY;

  if (envKey == null) {
    throw new Error(
      "PixelArt API key is missing. Pass it using the 'apiKey' parameter " +
        'or set the PIXELART_API_KEY environment variable.',
    );
  }

  if (typeof envKey !== 'string') {
    throw new Error(
      'PixelArt API key must be a string. ' +
        'The value of the PIXELART_API_KEY environment variable is not a string.',
    );
  }

  return envKey;
}

// ---------------------------------------------------------------------------
// Factory function
// ---------------------------------------------------------------------------

/**
 * Create a PixelArt provider instance.
 *
 * @example
 * ```ts
 * import { createPixelArt } from '@ai-sdk/pixelart';
 * import { generateImage } from 'ai';
 *
 * const pixelart = createPixelArt({ apiKey: process.env.PIXELART_API_KEY });
 *
 * const { images } = await generateImage({
 *   model: pixelart.image('pixelart-standard'),
 *   prompt: 'A tiny dragon perched on a treasure chest',
 *   providerOptions: {
 *     pixelart: { style: 'pixel', pixelDensity: 4 },
 *   },
 * });
 * ```
 */
export function createPixelArt(
  options: PixelArtProviderSettings = {},
): PixelArtProvider {
  const baseURL = withoutTrailingSlash(options.baseURL ?? defaultBaseURL);

  const getHeaders = () =>
    withUserAgentSuffix(
      {
        Authorization: `Bearer ${loadPixelArtApiKey({ apiKey: options.apiKey })}`,
        ...options.headers,
      },
      `ai-sdk/pixelart/${VERSION}`,
    );

  const createImageModel = (modelId: PixelArtImageModelId): ImageModelV3 =>
    new PixelArtImageModel(modelId, {
      provider: 'pixelart.image',
      baseURL: baseURL ?? defaultBaseURL,
      headers: getHeaders,
      fetch: options.fetch,
    });

  return {
    specificationVersion: 'v3' as const,

    // Image generation — the only supported modality
    image: createImageModel,
    imageModel: createImageModel,

    // Unsupported modalities — throw descriptive errors
    languageModel: (modelId: string) => {
      throw new NoSuchModelError({ modelId, modelType: 'languageModel' });
    },
    embeddingModel: (modelId: string) => {
      throw new NoSuchModelError({ modelId, modelType: 'embeddingModel' });
    },
  };
}

/**
 * Default PixelArt provider instance (reads API key from `PIXELART_API_KEY`).
 */
export const pixelart = createPixelArt();

